4179	\subsection{qcqs section localization and Stacks 01XJ}
4180	\label{sec:quot_qcqs_section_localization}
4181	
4182	The T12 session (2026-07-03) closed the \Cref{lem:pushforward_isQuasicoherent}
4183	pin. The route generalizes the affine section-localization keystone to
4184	quasi-compact quasi-separated opens by a Mayer--Vietoris induction, then runs
4185	the tilde--$\Gamma$ comparison backwards at each affine open of the base.
4186	
4187	\begin{lemma}[Affine basic-open section localization for quasi-coherent modules]
4188	  \label{lem:qcoh_section_localization_basicOpen}
4189	  \lean{AlgebraicGeometry.Scheme.Modules.isLocalizedModule_basicOpen}
4190	  \leanok
4191	  \textit{Source: Stacks~\href{https://stacks.math.columbia.edu/tag/01IB}{01IB}
4192	  / Hartshorne II.5.3 (\texttt{lemma-invert-f-sections}, affine case).}
4193	  Let $X$ be a scheme, $\mathcal{M}$ a quasi-coherent
4194	  $\mathcal{O}_X$-module, $U \subseteq X$ an affine open, and
4195	  $f \in \Gamma(X, U)$. Then the section restriction
4196	  $\Gamma(\mathcal{M}, U) \to \Gamma(\mathcal{M}, D(f))$ exhibits the target as
4197	  the localization $\Gamma(\mathcal{M}, U)[1/f]$ over $\Gamma(X, U)$.
4198	\end{lemma}
4199	\begin{proof}
4200	  \leanok
4201	  Pull $\mathcal{M}$ back along the affine immersion
4202	  $\operatorname{Spec} \Gamma(X, U) \to X$; the pullback is quasi-coherent
4203	  (pullback along an open immersion preserves quasi-coherence), so its
4204	  tilde--$\Gamma$ counit is an isomorphism, identifying it with
4205	  $\widetilde{\Gamma(\mathcal{M}, U)}$; the sections of a tilde over a basic
4206	  open are the localization, and the section comparison transports the
4207	  statement back to $X$.
4208	\end{proof}
4209	
4210	\begin{lemma}[qcqs section localization, torsion half]
4211	  \label{lem:qcqs_section_localization_torsion}
4212	  \lean{AlgebraicGeometry.Scheme.Modules.exists_pow_smul_res_eq_zero_of_isCompact}
4213	  \leanok
4214	  \uses{lem:qcoh_section_localization_basicOpen}
4215	  \textit{Source: Stacks~\href{https://stacks.math.columbia.edu/tag/01P0}{01P0}
4216	  (first half).}
4217	  Let $X$ be a scheme, $\mathcal{M}$ a quasi-coherent $\mathcal{O}_X$-module,
4218	  $W \subseteq X$ open, $g \in \Gamma(X, W)$, and $U \le W$ a quasi-compact
4219	  open. If $x \in \Gamma(\mathcal{M}, U)$ restricts to zero on
4220	  $U \cap D(g)$, then $(g|_U)^n \cdot x = 0$ for some $n \in \mathbb{N}$.
4221	\end{lemma}
4222	\begin{proof}
4223	  \leanok
4224	  \uses{lem:qcoh_section_localization_basicOpen}
4225	  Induction on the quasi-compact open $U$, adding one affine open at a time.
4226	  For $U = \emptyset$ the section vanishes by sheaf separation over the empty
4227	  cover. For $U = S \cup V$ with $V$ affine and the claim known on the
4228	  quasi-compact $S$: the restriction of $x$ to $S$ is killed by a power of
4229	  $g|_S$ by induction, and the restriction to $V$ is killed by a power of
4230	  $g|_V$ by the injectivity half of
4231	  \Cref{lem:qcoh_section_localization_basicOpen} at the affine $V$ (note
4232	  $D(g|_V) = V \cap D(g)$). Taking the maximum $n$ of the two exponents,
4233	  $(g|_U)^n \cdot x$ restricts to zero on both members of the cover
4234	  $\{S, V\}$, hence vanishes by sheaf separation.
4235	\end{proof}
4236	
4237	\begin{lemma}[qcqs section localization, surjectivity half]
4238	  \label{lem:qcqs_section_localization_surj}
4239	  \lean{AlgebraicGeometry.Scheme.Modules.exists_res_eq_pow_smul_of_isCompact}
4240	  \leanok
4241	  \uses{lem:qcoh_section_localization_basicOpen, lem:qcqs_section_localization_torsion}
4242	  \textit{Source: Stacks~\href{https://stacks.math.columbia.edu/tag/01P0}{01P0}
4243	  (second half).}
4244	  Let $X$, $\mathcal{M}$, $W$, $g$ be as above, with $W$ quasi-separated, and
4245	  let $U \le W$ be quasi-compact. For every
4246	  $y \in \Gamma(\mathcal{M}, U \cap D(g))$ there are $n \in \mathbb{N}$ and
4247	  $x \in \Gamma(\mathcal{M}, U)$ with
4248	  $x|_{U \cap D(g)} = (g|_{U \cap D(g)})^n \cdot y$.
4249	\end{lemma}
4250	\begin{proof}
4251	  \leanok
4252	  \uses{lem:qcoh_section_localization_basicOpen, lem:qcqs_section_localization_torsion}
4253	  Induction on the quasi-compact $U$ as in
4254	  \Cref{lem:qcqs_section_localization_torsion}. In the step $U = S \cup V$
4255	  ($V$ affine), the induction hypothesis and the affine surjectivity half of
4256	  \Cref{lem:qcoh_section_localization_basicOpen} produce candidate sections
4257	  $x_S$ on $S$ and $x_V$ on $V$ with a common normalization exponent $n$.
4258	  Their difference on the overlap $S \cap V$ --- quasi-compact because $W$ is
4259	  quasi-separated --- restricts to zero on $(S \cap V) \cap D(g)$, so by the
4260	  torsion half a further power $g^m$ kills it; after multiplying both
4261	  candidates by $g^m$ they agree on the overlap and glue to a section $x$
4262	  over $U$ with $x|_{U \cap D(g)} = g^{n+m} \cdot y$, checked by sheaf
4263	  separation over the cover $\{S \cap D(g), D(g|_V)\}$ of $U \cap D(g)$.
4264	\end{proof}
4265	
4266	\begin{lemma}[qcqs section localization]
4267	  \label{lem:qcqs_section_localization}
4268	  \lean{AlgebraicGeometry.Scheme.Modules.isLocalizedModule_basicOpen_of_isCompact}
4269	  \leanok
4270	  \uses{lem:qcqs_section_localization_torsion, lem:qcqs_section_localization_surj}
4271	  \textit{Source: Stacks~\href{https://stacks.math.columbia.edu/tag/01P0}{01P0}.}
4272	  Let $X$ be a scheme, $\mathcal{M}$ a quasi-coherent $\mathcal{O}_X$-module,
4273	  and $W \subseteq X$ a quasi-compact, quasi-separated open. For every
4274	  $g \in \Gamma(X, W)$ the section restriction
4275	  $\Gamma(\mathcal{M}, W) \to \Gamma(\mathcal{M}, D(g))$ exhibits the target
4276	  as the localization $\Gamma(\mathcal{M}, W)[1/g]$ over $\Gamma(X, W)$.
4277	\end{lemma}
4278	\begin{proof}
4279	  \leanok
4280	  \uses{lem:qcqs_section_localization_torsion, lem:qcqs_section_localization_surj}
4281	  The element $g$ restricts to a unit of $\Gamma(X, D(g))$, so every power of
4282	  $g$ acts invertibly on $\Gamma(\mathcal{M}, D(g))$; the surjectivity and
4283	  torsion (injectivity) conditions of the localization are
4284	  \Cref{lem:qcqs_section_localization_surj} and
4285	  \Cref{lem:qcqs_section_localization_torsion} at $U := W$.
4286	\end{proof}
4287	
4288	\begin{lemma}[Converse tilde--$\Gamma$ transport at an affine open]
4289	  \label{lem:fromTildeGamma_pullback_fromSpec_converse}
4290	  \lean{AlgebraicGeometry.Scheme.Modules.isIso_fromTildeΓ_pullback_fromSpec_of_isLocalizedModule}
4291	  \leanok
4292	  \uses{lem:qcoh_section_localization_basicOpen}
4293	  Let $Y$ be a scheme, $\mathcal{N}$ an $\mathcal{O}_Y$-module, and
4294	  $U \subseteq Y$ an affine open with canonical immersion
4295	  $j : \operatorname{Spec} \Gamma(Y, U) \to Y$. If for every
4296	  $f' \in \Gamma(Y, U)$ the restriction
4297	  $\Gamma(\mathcal{N}, U) \to \Gamma(\mathcal{N}, D(f'))$ is a localization at
4298	  the powers of $f'$ over $\Gamma(Y, U)$, then the tilde--$\Gamma$ counit of
4299	  the pullback $j^* \mathcal{N}$ is an isomorphism.
4300	\end{lemma}
4301	\begin{proof}
4302	  \leanok
4303	  The sections of $j^* \mathcal{N}$ over an open of the spectrum are the
4304	  sections of $\mathcal{N}$ over its image ($j$ is an open immersion), with
4305	  $j''(\top) = U$ and $j''(D(f')) = D(f')$; under these identifications --
4306	  which are semilinear over the canonical section-ring comparisons, by the
4307	  naturality of the immersion's application isomorphisms -- the hypothesis
4308	  says exactly that all basic-open section restrictions of $j^* \mathcal{N}$
4309	  on the spectrum are localizations, which characterizes the invertibility of
4310	  the tilde--$\Gamma$ counit.
4311	\end{proof}
4312	
4313	\begin{lemma}[Pushforward basic-open section localization]
4314	  \label{lem:pushforward_section_localization}
4315	  \lean{AlgebraicGeometry.Scheme.Modules.isLocalizedModule_basicOpen_pushforward}
4316	  \leanok
4317	  \uses{lem:qcqs_section_localization}
4318	  Let $\pi : X \to S$ be a quasi-compact, quasi-separated morphism of
4319	  schemes, $\mathcal{F}$ a quasi-coherent $\mathcal{O}_X$-module,
4320	  $U \subseteq S$ an affine open, and $f' \in \Gamma(S, U)$. Then the section
4321	  restriction
4322	  $\Gamma(\pi_* \mathcal{F}, U) \to \Gamma(\pi_* \mathcal{F}, D(f'))$ is a
4323	  localization at the powers of $f'$ over $\Gamma(S, U)$.
4324	\end{lemma}
4325	\begin{proof}
4326	  \leanok
4327	  \uses{lem:qcqs_section_localization}
4328	  The preimage $W := \pi^{-1}(U)$ is quasi-compact and quasi-separated
4329	  ($\pi$ is qcqs and $U$ is affine), and
4330	  $\pi^{-1}(D_S(f')) = D_X(g)$ for $g := \pi^\sharp f' \in \Gamma(X, W)$. The
4331	  sections of the pushforward are by definition the sections of
4332	  $\mathcal{F}$ over these preimages, with the $\Gamma(S, U)$-action given
4333	  through $\pi^\sharp$, so the statement is
4334	  \Cref{lem:qcqs_section_localization} for $\mathcal{F}$ at $g$ over $W$,
4335	  read through $\pi^\sharp$ (a localization over the base ring restricts to a
4336	  localization along any ring map matching the multiplicative sets).
4337	\end{proof}
4338	
4339	\begin{lemma}[Pushforward of quasi-coherent modules is quasi-coherent (Stacks 01XJ)]
4340	  \label{lem:pushforward_isQuasicoherent}
4341	  \lean{AlgebraicGeometry.Scheme.Modules.pushforward_isQuasicoherent}
4342	  \leanok
4343	  \textit{Source: Stacks~\href{https://stacks.math.columbia.edu/tag/01XJ}{01XJ}
4344	  (preservation of quasi-coherence under pushforward).}
4345	  Let \(f : X \to Y\) be a quasi-compact, quasi-separated morphism of
4346	  schemes, and let \(\mathcal{F}\) be a quasi-coherent
4347	  \(\mathcal{O}_X\)-module. Then \(f_* \mathcal{F}\) is a quasi-coherent
4348	  \(\mathcal{O}_Y\)-module. Mathlib \texttt{b80f227} ships no
4349	  \texttt{IsQuasicoherent.pushforward} instance at the
4350	  \texttt{Scheme.Modules} layer.
4351	\end{lemma}
4352	\begin{proof}
4353	  \leanok
4354	  \uses{lem:pushforward_section_localization, lem:fromTildeGamma_pullback_fromSpec_converse}
4355	  Quasi-coherence is local on $Y$, so it suffices to produce a presentation
4356	  of the slice of $f_* \mathcal{F}$ over each affine open $U \subseteq Y$.
4357	  By \Cref{lem:pushforward_section_localization} all basic-open section
4358	  restrictions of $f_* \mathcal{F}$ at $U$ are localizations, so by
4359	  \Cref{lem:fromTildeGamma_pullback_fromSpec_converse} the pullback of
4360	  $f_* \mathcal{F}$ along $\operatorname{Spec} \Gamma(Y, U) \to Y$ is
4361	  isomorphic to the tilde of its global sections. A tilde admits a global
4362	  presentation; transporting it along
4363	  $U \hookrightarrow Y = (\operatorname{Spec}\Gamma(Y,U) \cong U)
4364	  \hookrightarrow Y$ yields a presentation of the geometric restriction of
4365	  $f_* \mathcal{F}$ to $U$, hence of the slice. (The previously sketched
4366	  ``right adjoints preserve quasi-coherence'' argument is not a proof:
4367	  adjointness yields colimit preservation only.)
4368	\end{proof}
