cd /home/Axel/LeanAlgebraicGeometry-Horizon/MainProjects/Algebraic-Jacobian-Challenge/blueprint/src && ls chapters/ && echo "---ALL CREF TARGETS NOT DEFINED ANYWHERE---" && python3 - <<'EOF'
import re, glob

files = glob.glob('chapters/*.tex') + glob.glob('*.tex')
labels = set()
crefs = {}  # target -> list of (file, lineno)

for fn in files:
    with open(fn) as f:
        for i, line in enumerate(f, 1):
            # strip comments (naive: % not preceded by backslash)
            line2 = re.sub(r'(?<!\\)%.*', '', line)
            for m in re.finditer(r'\\label\{([^}]*)\}', line2):
                labels.add(m.group(1))
            for m in re.finditer(r'\\[cC]ref\{([^}]*)\}', line2):
                for tgt in m.group(1).split(','):
                    crefs.setdefault(tgt.strip(), []).append((fn, i))

dangling = {t: locs for t, locs in crefs.items() if t not in labels}
for t in sorted(dangling):
    print(t)
    for fn, i in dangling[t]:
        print(f"    {fn}:{i}")
EOF

